import { Component, Input, Output, EventEmitter, ViewChild, ElementRef } from '@angular/core';

@Component({
  selector: 'app-photo-upload',
  templateUrl: './photo-upload.component.html',
  styleUrls: ['./photo-upload.component.scss']
})
export class PhotoUploadComponent {
  @ViewChild('fileInput') fileInputRef!: ElementRef<HTMLInputElement>;
  @Input() label    = 'Applicant';
  @Input() sublabel = '';
  @Input() mandatory = false;
  @Output() photoSelected = new EventEmitter<string>();
  @Output() photoCleared  = new EventEmitter<void>();

  previewUrl: string | null = null;
  hasError = false;
  showMandatoryError = false;

  onFileChange(e: Event): void {
    const file = (e.target as HTMLInputElement).files?.[0];
    if (!file) return;
    if (!file.type.startsWith('image/') || file.size > 5 * 1024 * 1024) { this.hasError = true; return; }
    this.hasError = false;
    this.showMandatoryError = false;
    const reader = new FileReader();
    reader.onload = (ev) => { this.previewUrl = ev.target?.result as string; this.photoSelected.emit(this.previewUrl); };
    reader.readAsDataURL(file);
  }

  clear(): void {
    this.previewUrl = null; this.hasError = false; this.showMandatoryError = false;
    if (this.fileInputRef?.nativeElement) this.fileInputRef.nativeElement.value = '';
    this.photoCleared.emit();
  }

  /** Called by parent during form validation to highlight if mandatory + empty */
  triggerValidation(): boolean {
    if (this.mandatory && !this.previewUrl) {
      this.showMandatoryError = true;
      return false;
    }
    return true;
  }

  trigger(): void { this.fileInputRef?.nativeElement.click(); }
}
<div class="photo-box">
  <div class="photo-label-top">
    {{ label }}<span *ngIf="sublabel" class="photo-sublabel">{{ sublabel }}</span>
    <span class="req" *ngIf="mandatory">*</span>
  </div>
  <div class="photo-upload" [class.has-photo]="!!previewUrl" [class.photo-error-border]="hasError || showMandatoryError" (click)="trigger()">
    <input #fileInput type="file" accept="image/*" style="display:none" (change)="onFileChange($event)"/>
    <img *ngIf="previewUrl" [src]="previewUrl" class="photo-preview" alt="Preview"/>
    <div class="photo-placeholder" *ngIf="!previewUrl">
      <div class="ph-icon">🖼</div>
      <div class="ph-text">Tap to upload</div>
      <div class="ph-hint">JPG / PNG · Max 5MB</div>
    </div>
    <div class="photo-overlay" *ngIf="previewUrl"><span>Change</span></div>
  </div>
  <button *ngIf="previewUrl" class="photo-clear-btn" type="button" (click)="$event.stopPropagation(); clear()">✕ Remove</button>
  <div class="photo-err-text" *ngIf="hasError">Use JPG/PNG under 5MB</div>
  <div class="photo-err-text" *ngIf="showMandatoryError && !previewUrl">Photo is required.</div>
</div>
